import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Use ProcessBuilder with separate arguments to avoid Command Injection
            Process process = new ProcessBuilder("ping", command).start();

            BufferedReader inputStream = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String output = "";
            String line;

            while ((line = inputStream.readLine()) != null) {
                output += line + "\n";
            }

            System.out.println("Output of command:\n" + output);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

